#include "SYsULexer.h" // 确保这里的头文件名与您生成的词法分析器匹配
#include <fstream>
#include <iostream>
#include <unordered_map>
#include <string>
#include <vector>
#include <sstream>

// 全局变量跟踪预处理信息
static std::string currentFileName = "";
static int markerLineNum = 1;  // 预处理标记中的行号
static int firstCodeAntlrLine = -1; // 第一个代码token的ANTLR行号
static int prevTokenEndCol = 0; // 前一个token的结束列号（用于判断LeadingSpace）
static int prevTokenLine = 0;   // 前一个token的行号

// 映射定义，将ANTLR的tokenTypeName映射到clang的格式
std::unordered_map<std::string, std::string> tokenTypeMapping = {
  // Keywords
  { "Int", "int" },
  { "Return", "return" },
  { "While", "while" },
  { "If", "if" },
  { "Else", "else" },
  { "Break", "break" },
  { "Continue", "continue" },
  { "Const", "const" },
  { "Void", "void" },

  // Identifiers and constants
  { "Identifier", "identifier" },
  { "Constant", "numeric_constant" },

  // Punctuators
  { "LeftParen", "l_paren" },
  { "RightParen", "r_paren" },
  { "LeftBrace", "l_brace" },
  { "RightBrace", "r_brace" },
  { "LeftBracket", "l_square" },
  { "RightBracket", "r_square" },
  { "Semi", "semi" },
  { "Comma", "comma" },

  // Operators
  { "Plus", "plus" },
  { "Minus", "minus" },
  { "Star", "star" },
  { "Slash", "slash" },
  { "Percent", "percent" },
  { "Less", "less" },
  { "LessEqual", "lessequal" },
  { "Greater", "greater" },
  { "GreaterEqual", "greaterequal" },
  { "Equal", "equal" },
  { "EqualEqual", "equalequal" },
  { "Exclaim", "exclaim" },
  { "ExclaimEqual", "exclaimequal" },
  { "AmpAmp", "ampamp" },
  { "PipePipe", "pipepipe" },

  // Bitwise operators
  { "Amp", "amp" },
  { "Pipe", "pipe" },
  { "Caret", "caret" },
  { "Tilde", "tilde" },

  // Shift operators
  { "LessLess", "lessless" },
  { "GreaterGreater", "greatergreater" },

  // Special
  { "EOF", "eof" },
  { "LineAfterPreprocessing", "line_marker" }
};

// 解析预处理行标记，更新当前文件名和行号
void process_line_marker(const std::string& marker) {
  // 查找引号包围的文件名
  size_t firstQuote = marker.find('"');
  if (firstQuote == std::string::npos) {
    return; // 没有文件名，可能是系统头文件标记
  }

  size_t secondQuote = marker.find('"', firstQuote + 1);
  if (secondQuote == std::string::npos) {
    return; // 没有结束引号
  }

  std::string filename = marker.substr(firstQuote + 1, secondQuote - firstQuote - 1);

  // 提取行号（#后面的第一个数字）
  size_t numStart = marker.find_first_of("0123456789");
  if (numStart == std::string::npos) {
    return;
  }

  size_t numEnd = marker.find_first_not_of("0123456789", numStart);
  std::string lineNumStr = marker.substr(numStart, numEnd - numStart);
  int lineNum = std::stoi(lineNumStr);

  // 只更新实际源文件的标记（不是系统头文件）
  if (filename.find("<") == std::string::npos) { // 不是 <built-in> 等系统头文件
    currentFileName = filename;
    markerLineNum = lineNum;
  }
}

void
print_token(const antlr4::Token* token,
            const antlr4::CommonTokenStream& tokens,
            std::ofstream& outFile,
            const antlr4::Lexer& lexer)
{
  auto& vocabulary = lexer.getVocabulary();

  auto tokenTypeName =
    std::string(vocabulary.getSymbolicName(token->getType()));

  if (tokenTypeName.empty())
    tokenTypeName = "<UNKNOWN>"; // 处理可能的空字符串情况

  // 处理预处理行标记
  if (tokenTypeName == "LineAfterPreprocessing") {
    process_line_marker(token->getText());
    return; // 不输出预处理标记
  }

  if (tokenTypeMapping.find(tokenTypeName) != tokenTypeMapping.end()) {
    tokenTypeName = tokenTypeMapping[tokenTypeName];
  }

  // 计算位置信息
  int line = token->getLine();
  int column = token->getCharPositionInLine() + 1; // ANTLR 从0开始，clang从1开始

  // 记录第一个代码token的ANTLR行号
  if (firstCodeAntlrLine == -1 && tokenTypeName != "line_marker") {
    firstCodeAntlrLine = line;
  }

  // 调整行号：考虑预处理行标记的偏移
  int adjustedLine;
  if (firstCodeAntlrLine != -1) {
    adjustedLine = markerLineNum + (line - firstCodeAntlrLine);
  } else {
    adjustedLine = line;
  }

  std::string locInfo;
  if (tokenTypeName == "eof") {
    // EOF 的特殊处理：行号+1，列号1
    locInfo = " Loc=<" + currentFileName + ":" + std::to_string(adjustedLine + 1) + ":1>";
  } else {
    locInfo = " Loc=<" + currentFileName + ":" + std::to_string(adjustedLine) + ":" + std::to_string(column) + ">";
  }

  // 判断 StartOfLine 和 LeadingSpace
  bool startOfLine = (line != prevTokenLine); // 新行的第一个token
  bool leadingSpace = false;

  if (line == prevTokenLine) {
    // 在同一行，检查是否紧接前一个token
    // 如果当前token的起始列号 > 前一个token的结束列号 + 1，则中间有空格
    if (column > prevTokenEndCol + 1) {
      leadingSpace = true;
    }
  } else if (column > 1) {
    // 新行但不在列1（有缩进），前面有空格
    leadingSpace = true;
  }

  // 更新前一个token的信息（用于下一个token的判断）
  if (tokenTypeName != "line_marker") {
    prevTokenLine = line;
    prevTokenEndCol = column + token->getText().length() - 1;
  }

  // 输出 token
  outFile << tokenTypeName << " '" << (token->getText() == "<EOF>" ? "" : token->getText()) << "'";

  // 输出标记
  if (startOfLine)
    outFile << "\t[StartOfLine]";
  if (leadingSpace)
    outFile << "\t[LeadingSpace]";

  // 输出位置信息
  outFile << "\t" << locInfo << std::endl;
}

int
main(int argc, char* argv[])
{
  if (argc != 3) {
    std::cout << "Usage: " << argv[0] << " <input> <output>\n";
    return -1;
  }

  std::ifstream inFile(argv[1]);
  if (!inFile) {
    std::cout << "Error: unable to open input file: " << argv[1] << '\n';
    return -2;
  }

  std::ofstream outFile(argv[2]);
  if (!outFile) {
    std::cout << "Error: unable to open output file: " << argv[2] << '\n';
    return -3;
  }

  // 重置全局变量
  currentFileName = "";
  markerLineNum = 1;
  firstCodeAntlrLine = -1;
  prevTokenEndCol = 0;
  prevTokenLine = 0;

  antlr4::ANTLRInputStream input(inFile);
  SYsULexer lexer(&input);

  antlr4::CommonTokenStream tokens(&lexer);
  tokens.fill();

  for (auto&& token : tokens.getTokens()) {
    print_token(token, tokens, outFile, lexer);
  }

  return 0;
}

